import React, { useState, useEffect } from 'react';
import axios from 'axios';

const API_URL = 'http://localhost:9000';

const Dashboard = ({ token }) => {
    const [portfolio, setPortfolio] = useState([]);

    useEffect(() => {
        axios.get(`${API_URL}/price-history/AAPL`, {
            headers: { Authorization: `Bearer ${token}` }
        })
            .then(res => {
                console.log("Données du portefeuille :", res.data); // 🔥 Vérifier si les données sont reçues
                setPortfolio(res.data);
            })
            .catch(err => {
                console.error("Erreur lors de la récupération du portefeuille :", err);
                setPortfolio([]);
            });
    }, [token]);

    return (
        <div className="container">
            <h2>Your Portfolio</h2>
            <ul>
                {portfolio.length > 0 ? (
                    portfolio.map((stock, index) => (
                        <li key={index}>{stock.symbol}: ${stock.price}</li>
                    ))
                ) : (
                    <p>No data available</p>
                )}
            </ul>
        </div>
    );
};

export default Dashboard;
